import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const RaiseComplaint = () => {
    const [formData, setFormData] = useState({
        department: '', programme: '', block: '', blockName: '', roomNumber: '', 
        complaintType: 'PC Hardware', complaintRemarks: '', attachment: ''
    });
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [blocks, setBlocks] = useState([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchDepartments();
    }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            alert('Error fetching departments');
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            alert('Error fetching programmes');
        }
    };

    const fetchBlocks = async (progId) => {
        try {
            const { data } = await API.get('/master/block');
            const filtered = data.filter(b => b.programme && b.programme._id === progId);
            setBlocks(filtered);
            setFormData(prev => ({...prev, block: '', blockName: ''}));
        } catch (err) {
            alert('Error fetching blocks');
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData(prev => ({...prev, department: deptId, programme: '', block: ''}));
        if (deptId) fetchProgrammes(deptId);
    };

    const handleProgrammeChange = (e) => {
        const progId = e.target.value;
        setFormData(prev => ({...prev, programme: progId, block: ''}));
        if (progId) fetchBlocks(progId);
    };

    const handleBlockChange = (e) => {
        const blockId = e.target.value;
        const selectedBlock = blocks.find(b => b._id === blockId);
        setFormData(prev => ({...prev, block: blockId, blockName: selectedBlock?.blockName || ''}));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/complaints', formData);
            alert("Complaint submitted successfully!");
        } catch (err) {
            alert("Error raising complaint: " + (err.response?.data?.error || err.message));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '20px' }}>Raise a Ticket</h2>
            <form onSubmit={handleSubmit} style={{ display: 'grid', gap: '15px', maxWidth: '500px' }}>
                <div>
                    <label>Department</label>
                    <select 
                        required
                        value={formData.department}
                        onChange={handleDepartmentChange}
                        style={inputStyle}
                    >
                        <option value="">Select Department</option>
                        {departments.map(d => <option key={d._id} value={d._id}>{d.department}</option>)}
                    </select>
                </div>

                <div>
                    <label>Programme</label>
                    <select 
                        required
                        value={formData.programme}
                        onChange={handleProgrammeChange}
                        style={inputStyle}
                    >
                        <option value="">Select Programme</option>
                        {programmes.map(p => <option key={p._id} value={p._id}>{p.programme}</option>)}
                    </select>
                </div>

                <div>
                    <label>Block</label>
                    <select 
                        required
                        value={formData.block}
                        onChange={handleBlockChange}
                        style={inputStyle}
                    >
                        <option value="">Select Block</option>
                        {blocks.map(b => <option key={b._id} value={b._id}>{b.blockName}</option>)}
                    </select>
                </div>

                <div>
                    <label>Room Number</label>
                    <input type="text" placeholder="Room Number" required 
                        value={formData.roomNumber}
                        onChange={e => setFormData({...formData, roomNumber: e.target.value})} 
                        style={inputStyle} />
                </div>

                <div>
                    <label>Complaint Type</label>
                    <select 
                        value={formData.complaintType}
                        onChange={e => setFormData({...formData, complaintType: e.target.value})} 
                        style={inputStyle}
                    >
                        <option value="PC Hardware">PC Hardware</option>
                        <option value="PC Software">PC Software</option>
                        <option value="Application Issues">Application Issues</option>
                        <option value="Network">Network</option>
                        <option value="Electronics">Electronics</option>
                        <option value="Plumbing">Plumbing</option>
                    </select>
                </div>

                <div>
                    <label>Complaint Remarks</label>
                    <textarea placeholder="Describe the issue..." required 
                        value={formData.complaintRemarks}
                        onChange={e => setFormData({...formData, complaintRemarks: e.target.value})} 
                        style={{...inputStyle, height: '100px'}} />
                </div>

                <div>
                    <label>Attachment (Optional)</label>
                    <input type="text" placeholder="Attachment URL (optional)"
                        value={formData.attachment}
                        onChange={e => setFormData({...formData, attachment: e.target.value})} 
                        style={inputStyle} />
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>{loading ? 'Submitting...' : 'Submit Ticket'}</button>
            </form>
        </div>
    );
};

const inputStyle = { padding: '12px', borderRadius: '8px', border: '1px solid #334155', background: '#1e293b', color: 'white' };
const btnStyle = { padding: '15px', background: 'linear-gradient(to right, #38bdf8, #818cf8)', border: 'none', borderRadius: '8px', color: 'white', fontWeight: 'bold', cursor: 'pointer' };

export default RaiseComplaint;
